// // This SR flip-flop will set Q to 0 when S is high and R is low, and reset Q to 1 when S is low and R is high.
module sr_flip_flop (
    input wire S,
    input wire R,
    input wire CLK,
    output reg Q
);

    always @(posedge CLK) begin
        if (S && !R)
            Q <= 1'b1; // Set
        else if (!S && R)
            Q <= 1'b0; // Reset
        // If both S and R are low, do nothing (hold state)
        // If both S and R are high, the state is undefined
    end
endmodule
